import React, { useState, useCallback } from 'react';
import { Box, TextField, InputAdornment, IconButton, CircularProgress, useMediaQuery, useTheme } from '@mui/material';
import { Search, Clear, TuneRounded } from '@mui/icons-material';
import AdminPanelSettingsIcon from '@mui/icons-material/AdminPanelSettings';
import { useNavigate } from '@tanstack/react-router';
import { GetUserRoles, IsTokenValid } from '@/utils/token';
import { CallStatus, Roles } from '@/types/api.types';
import { StatusMessage } from '@/components/StatusMessage';
import { TabHeader } from '@/components/TabHeader';
import { SearchServices, SearchServicesError, ProfileServices } from '@/api';
import { ExtractCorrelationId } from '@/utils/common';
import ProfileResultsList from './components/ProfileResultsList';
import UpdateRoleDialog, { RoleDialogProfile } from './components/UpdateRoleDialog';
import { ProfileInfoDialog } from '@/components/ProfileInfoDialog';
import { PublicProfileResult } from '@/types/profile.types';
import { UnifiedSearchResult } from '@/types/search.types';

type RoleProfileItem = PublicProfileResult & { roles?: Roles[] };

export function RoleManagement() {
    const navigate = useNavigate();
    const theme = useTheme();
    const isMobile = useMediaQuery(theme.breakpoints.down('sm'));

    const [query, setQuery] = useState('');
    const [searchedQuery, setSearchedQuery] = useState('');
    const [profiles, setProfiles] = useState<RoleProfileItem[]>([]);
    const [searchStatus, setSearchStatus] = useState<CallStatus>(CallStatus.NotStarted);
    const [httpStatus, setHttpStatus] = useState<number>(0);
    const [correlationId, setCorrelationId] = useState<string | undefined>(undefined);
    const [selectedProfile, setSelectedProfile] = useState<RoleProfileItem | null>(null);
    const [isDialogOpen, setIsDialogOpen] = useState(false);
    const [infoProfileId, setInfoProfileId] = useState<string | null>(null);

    // Check authorization
    React.useEffect(() => {
        const isValid = IsTokenValid();
        if (!isValid) {
            navigate({ to: '/' });
            return;
        }

        const userRoles = GetUserRoles();
        const isAdmin = userRoles.includes(Roles.Admin) || userRoles.includes(Roles.SuperAdmin);
        if (!isAdmin) {
            navigate({ to: '/' });
        }
    }, [navigate]);

    const trimmedQuery = query.trim();
    const canSearch = trimmedQuery.length >= 2;
    const isSearching = searchStatus === CallStatus.InProgress;

    const executeSearch = async () => {
        if (!canSearch) return;
        setSearchedQuery(trimmedQuery);
        setSearchStatus(CallStatus.InProgress);
        try {
            const response = await SearchServices.UnifiedSearch(trimmedQuery, { pageNumber: 1, pageSize: 50 });
            setHttpStatus(response.data.status);
            setCorrelationId(ExtractCorrelationId(response));
            if (response.data.status >= 200 && response.data.status < 300) {
                const result: UnifiedSearchResult = response.data.result;
                const baseProfiles = (result.profiles?.items || []) as RoleProfileItem[];
                // Search index doesn't include roles — fetch admin profile per result to get roles.
                const enriched = await Promise.all(baseProfiles.map(async (p) => {
                    try {
                        const r = await ProfileServices.GetAdminProfileById(p.id);
                        const roles = r?.data?.result?.roles as Roles[] | undefined;
                        return { ...p, roles: roles ?? [] };
                    } catch {
                        return { ...p, roles: [] as Roles[] };
                    }
                }));
                setProfiles(enriched);
                setSearchStatus(CallStatus.Success);
            } else {
                setProfiles([]);
                setSearchStatus(CallStatus.Failure);
            }
        } catch {
            setProfiles([]);
            setSearchStatus(CallStatus.Failure);
        }
    };

    const handleClear = () => {
        setQuery('');
        setSearchedQuery('');
        setProfiles([]);
        setSearchStatus(CallStatus.NotStarted);
        setHttpStatus(0);
        setCorrelationId(undefined);
    };

    const handleEditRole = useCallback((profile: RoleProfileItem) => {
        setSelectedProfile(profile);
        setIsDialogOpen(true);
    }, []);

    const handleCloseDialog = useCallback(() => {
        setIsDialogOpen(false);
        setSelectedProfile(null);
    }, []);

    const handleRoleUpdateSuccess = useCallback((updated: RoleDialogProfile) => {
        setProfiles(prev =>
            prev.map(p => (p.id === updated.id ? { ...p, roles: updated.roles } : p))
        );
        handleCloseDialog();
    }, [handleCloseDialog]);

    return (
        <>
            <TabHeader
                icon={<AdminPanelSettingsIcon color="primary" />}
                title="Role management"
                subtitle="Search alumni and assign or revoke administrative roles."
            />
            {/* Home-style search bar */}
            <Box sx={{ display: 'flex', flexDirection: 'column', alignItems: 'center', pt: 2, pb: 2 }}>
                <Box sx={{ width: '100%', maxWidth: 580, px: isMobile ? 1 : 0 }}>
                    <TextField
                        fullWidth
                        placeholder="Search profile by name, phone, batch..."
                        value={query}
                        onChange={(e) => setQuery(e.target.value)}
                        onKeyDown={(e) => { if (e.key === 'Enter') { e.preventDefault(); executeSearch(); } }}
                        disabled={isSearching}
                        sx={{
                            '& .MuiOutlinedInput-root': {
                                borderRadius: '24px',
                                height: isMobile ? 48 : 52,
                                px: 1,
                                bgcolor: '#ffffff',
                                border: '1px solid #dfe1e5',
                                boxShadow: 'none',
                                '&:hover': { bgcolor: '#ffffff', boxShadow: '0 2px 8px 1px rgba(64,60,67,.16)', borderColor: 'transparent' },
                                '&.Mui-focused': { bgcolor: '#ffffff', boxShadow: '0 2px 8px 1px rgba(64,60,67,.16)', borderColor: 'transparent' },
                                '& fieldset': { border: 'none' },
                            },
                        }}
                        slotProps={{
                            input: {
                                startAdornment: (
                                    <InputAdornment position="start">
                                        <IconButton
                                            size="small"
                                            sx={{ color: '#fff', bgcolor: 'primary.main', '&:hover': { bgcolor: 'primary.dark' } }}
                                            disabled
                                        >
                                            <TuneRounded fontSize="small" />
                                        </IconButton>
                                    </InputAdornment>
                                ),
                                endAdornment: (
                                    <InputAdornment position="end">
                                        {query && (
                                            <IconButton size="small" onClick={handleClear} disabled={isSearching}>
                                                <Clear fontSize="small" />
                                            </IconButton>
                                        )}
                                        {isSearching ? (
                                            <CircularProgress size={20} sx={{ ml: 0.5 }} />
                                        ) : (
                                            <IconButton
                                                size="small"
                                                onClick={executeSearch}
                                                disabled={!canSearch}
                                                color="primary"
                                            >
                                                <Search />
                                            </IconButton>
                                        )}
                                    </InputAdornment>
                                ),
                            },
                            htmlInput: { maxLength: 100 },
                        }}
                    />
                </Box>
            </Box>

            <StatusMessage
                notStartedMessage=""
                successMessage={searchedQuery ? `${profiles.length} result(s) found for "${searchedQuery}".` : undefined}
                failureMessage={SearchServicesError.UnifiedSearchError(httpStatus)}
                currentStatus={searchStatus}
                correlationId={correlationId}
            />

            {searchStatus === CallStatus.Success && (
                <ProfileResultsList
                    profiles={profiles as any}
                    isLoading={false}
                    onEditRole={handleEditRole}
                    onProfileClick={(p) => setInfoProfileId(p.id)}
                />
            )}

            {selectedProfile && (
                <UpdateRoleDialog
                    open={isDialogOpen}
                    profile={selectedProfile}
                    onClose={handleCloseDialog}
                    onSuccess={handleRoleUpdateSuccess}
                />
            )}

            <ProfileInfoDialog
                open={!!infoProfileId}
                profileId={infoProfileId ?? ''}
                mode="admin"
                onClose={() => setInfoProfileId(null)}
            />
        </>
    );
}
