import React from 'react';
import { Box, Typography, IconButton, Skeleton, Chip, Stack, Paper, Divider } from '@mui/material';
import EditIcon from '@mui/icons-material/Edit';
import SchoolIcon from '@mui/icons-material/School';
import EmailIcon from '@mui/icons-material/Email';
import PhoneIcon from '@mui/icons-material/Phone';
import BadgeIcon from '@mui/icons-material/Badge';
import LocationOnIcon from '@mui/icons-material/LocationOn';
import WorkIcon from '@mui/icons-material/Work';
import { ProfileResult } from '@/types/profile.types';
import { Roles } from '@/types/api.types';
import { compactChipSx } from '@/constants/ThemeConstants';

interface ProfileResultsListProps {
    profiles: ProfileResult[];
    isLoading: boolean;
    onEditRole: (profile: ProfileResult) => void;
    onProfileClick?: (profile: ProfileResult) => void;
}

const getRoleColor = (role: string): 'secondary' | 'info' | 'primary' | 'default' => {
    switch (role) {
        case Roles.SuperAdmin:
        case Roles.Admin:
            return 'secondary';
        case Roles.EventMgr: return 'info';
        default: return 'default';
    }
};

const getRoleVariant = (role: string): 'filled' | 'outlined' => {
    switch (role) {
        case Roles.SuperAdmin:
        case Roles.Admin:
            return 'filled';
        default:
            return 'outlined';
    }
};

const getAccentColor = (roles?: Roles[]): string => {
    if (!roles) return 'rgba(0,0,0,0.12)';
    if (roles.includes(Roles.SuperAdmin) || roles.includes(Roles.Admin)) return '#9c27b0';
    if (roles.includes(Roles.EventMgr)) return '#0288d1';
    return '#1976d2';
};

const ProfileResultsList: React.FC<ProfileResultsListProps> = ({ profiles, isLoading, onEditRole, onProfileClick }) => {
    if (isLoading) {
        return (
            <Box sx={{ display: 'flex', flexDirection: 'column', gap: 1.5 }}>
                {[1, 2, 3].map(i => (
                    <Paper key={i} sx={{ p: 2 }}>
                        <Skeleton variant="text" width="60%" />
                        <Skeleton variant="text" width="80%" />
                        <Skeleton variant="text" width="70%" />
                    </Paper>
                ))}
            </Box>
        );
    }

    if (profiles.length === 0) {
        return (
            <Typography variant="body1" color="textSecondary" sx={{ py: 4, textAlign: 'center' }}>
                No profiles found. Try a different search.
            </Typography>
        );
    }

    return (
        <Box sx={{ display: 'flex', flexDirection: 'column', gap: 1.5 }}>
            {profiles.map(profile => (
                <Box
                    key={profile.id}
                    sx={{
                        p: 2,
                        borderRadius: 2,
                        bgcolor: 'background.paper',
                        border: '1px solid',
                        borderColor: 'divider',
                        borderLeft: `4px solid ${getAccentColor(profile.roles)}`,
                        transition: 'box-shadow 0.2s',
                        '&:hover': { boxShadow: 2 },
                    }}
                >
                    {/* Name + Edit */}
                    <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', mb: 1 }}>
                        <Typography
                            variant="subtitle1"
                            onClick={onProfileClick ? () => onProfileClick(profile) : undefined}
                            sx={{
                                fontWeight: 600,
                                color: onProfileClick ? 'primary.main' : 'text.primary',
                                overflow: 'hidden',
                                textOverflow: 'ellipsis',
                                whiteSpace: 'nowrap',
                                cursor: onProfileClick ? 'pointer' : 'default',
                                '&:hover': onProfileClick ? { textDecoration: 'underline' } : undefined,
                            }}
                        >
                            {profile.name}
                        </Typography>
                        <IconButton size="small" onClick={() => onEditRole(profile)} sx={{ bgcolor: 'primary.main', color: 'primary.contrastText', flexShrink: 0, ml: 1, width: 32, height: 32, '&:hover': { bgcolor: 'primary.dark' } }}>
                            <EditIcon sx={{ fontSize: '1rem' }} />
                        </IconButton>
                    </Box>

                    {/* Meta grid */}
                    <Box sx={{ display: 'grid', gridTemplateColumns: { xs: '1fr', sm: '1fr 1fr' }, gap: 0.5, mb: 1.5 }}>
                        {profile.firstJnvName && (
                            <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.5 }}>
                                <SchoolIcon sx={{ fontSize: '0.95rem', color: 'text.disabled' }} />
                                <Typography variant="caption" sx={{ color: 'text.secondary' }}>
                                    {profile.firstJnvName}
                                </Typography>
                            </Box>
                        )}
                        {profile.batch > 0 && (
                            <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.5 }}>
                                <BadgeIcon sx={{ fontSize: '0.95rem', color: 'text.disabled' }} />
                                <Typography variant="caption" sx={{ color: 'text.secondary' }}>
                                    Batch {profile.batch}
                                </Typography>
                            </Box>
                        )}
                        {profile.email && (
                            <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.5, minWidth: 0 }}>
                                <EmailIcon sx={{ fontSize: '0.95rem', color: 'text.disabled', flexShrink: 0 }} />
                                <Typography variant="caption" sx={{ color: 'text.secondary', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                                    {profile.email}
                                </Typography>
                            </Box>
                        )}
                        {profile.phone && (
                            <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.5 }}>
                                <PhoneIcon sx={{ fontSize: '0.95rem', color: 'text.disabled' }} />
                                <Typography variant="caption" sx={{ color: 'text.secondary' }}>
                                    {profile.phone}
                                </Typography>
                            </Box>
                        )}
                        {profile.location && (
                            <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.5 }}>
                                <LocationOnIcon sx={{ fontSize: '0.95rem', color: 'text.disabled' }} />
                                <Typography variant="caption" sx={{ color: 'text.secondary' }}>
                                    {profile.location}
                                </Typography>
                            </Box>
                        )}
                        {profile.organisation && (
                            <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.5 }}>
                                <WorkIcon sx={{ fontSize: '0.95rem', color: 'text.disabled' }} />
                                <Typography variant="caption" sx={{ color: 'text.secondary' }}>
                                    {profile.organisation}
                                </Typography>
                            </Box>
                        )}
                    </Box>

                    <Divider sx={{ mb: 1, borderStyle: 'dashed' }} />

                    {/* Roles */}
                    <Stack direction="row" spacing={0.5} sx={{ flexWrap: 'wrap', gap: 0.5 }}>
                        {profile.roles && profile.roles.length > 0 ? (
                            profile.roles.map(role => (
                                <Chip
                                    key={role}
                                    label={role}
                                    size="small"
                                    color={getRoleColor(role)}
                                    variant={getRoleVariant(role)}
                                    sx={{
                                        ...compactChipSx,
                                        ...(getRoleVariant(role) === 'filled' && {
                                            color: '#fff !important',
                                            '& .MuiChip-label': { color: '#fff' },
                                        }),
                                    }}
                                />
                            ))
                        ) : (
                            <Typography variant="caption" sx={{ color: 'text.disabled' }}>
                                No roles assigned
                            </Typography>
                        )}
                    </Stack>
                </Box>
            ))}
        </Box>
    );
};

export default ProfileResultsList;
